/* ── Navigation arrows ── */
.deck-nav {
  position: fixed;
  top: 0;
  width: 35%;
  height: 100%;
  z-index: 5;
  cursor: pointer;
  display: flex;
  align-items: center;
  transition: opacity 0.3s;
  opacity: 0;
}
.deck-nav:hover { opacity: 1; }
.deck-nav.prev { left: 0; justify-content: flex-start; padding-left: 28px; }
.deck-nav.next { right: 0; justify-content: flex-end; padding-right: 28px; }
.deck-nav svg {
  width: 32px; height: 32px;
  color: var(--muted);
  transition: color 0.2s, transform 0.2s var(--ease-out);
  filter: drop-shadow(0 2px 8px rgba(0,0,0,0.3));
}
.deck-nav:hover svg { color: var(--accent); }
.deck-nav.prev:hover svg { transform: translateX(-4px); }
.deck-nav.next:hover svg { transform: translateX(4px); }
@media (max-width: 768px) {
  .deck-nav { width: 30%; }
  .deck-nav svg { width: 24px; height: 24px; }
}

/* ── Navigation dots ── */
.deck-dots {
  position: fixed;
  bottom: 28px;
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  gap: 8px;
  z-index: 10;
  pointer-events: none;
}
.deck-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--border);
  transition: background 0.3s, transform 0.3s var(--ease-out);
  pointer-events: auto;
  cursor: pointer;
}
.deck-dot.active { background: var(--accent); transform: scale(1.4); }
.slide.dark ~ .deck-dots .deck-dot { background: rgba(245,245,247,0.25); }
.slide.dark ~ .deck-dots .deck-dot.active { background: var(--accent); }

